export const STATES = [...new Set(UNIVERSITIES.map(u=>u.state))].sort().map(code=>{
  const names={TX:"Texas",CA:"California",NY:"New York",NC:"North Carolina",VA:"Virginia",AZ:"Arizona",MA:"Massachusetts",GA:"Georgia",FL:"Florida",IL:"Illinois",WA:"Washington",PA:"Pennsylvania",IN:"Indiana",OH:"Ohio",NJ:"New Jersey",UT:"Utah",CO:"Colorado",MD:"Maryland",MI:"Michigan",AL:"Alabama",OK:"Oklahoma",TN:"Tennessee",NE:"Nebraska",WI:"Wisconsin",IA:"Iowa",SC:"South Carolina",NM:"New Mexico",CT:"Connecticut",RI:"Rhode Island",NH:"New Hampshire",KS:"Kansas",MO:"Missouri",AR:"Arkansas",KY:"Kentucky",MS:"Mississippi",LA:"Louisiana",DC:"Washington DC"};
  return {code, name:names[code]||code};
});

export const tierBadgeClass = t => ({ELITE:"badge-elite",TIER2:"badge-t2",TIER3:"badge-t3",TIER4:"badge-t4",TIER5:"badge-t5"}[t] || "badge-t5");
export const tierLabel = t => ({ELITE:"Elite",TIER2:"Tier 2",TIER3:"Tier 3",TIER4:"Tier 4",TIER5:"Tier 5"}[t] || t);
export const admitMid = u => (u.admitL + u.admitH) / 2;
